def test_mobile_cheque_deposit_unauthenticated_returns_401(valid_cheque_image):
    payload = {
        "image": valid_cheque_image,
        "amount": 1000,
        "currency": "USD"
    }
    resp = <api_client>.post("/deposits/mobile-cheque", json=payload)
    assert resp.status_code == 401
    body = resp.json()
    assert body.get("error_code") == "UNAUTHORISED"
